#!/usr/bin/env python3
"""
Deployment automation script for CI/CD pipeline.
Installs dependencies, runs tests, and packages for deployment.
"""

import subprocess
import sys
import os
import shutil
import hashlib
import json
import tempfile
from datetime import datetime, timezone
from pathlib import Path


def run_command(cmd, description, check=True, capture_output=False):
    """Run a shell command with error handling."""
    print(f"\n{'='*60}")
    print(f"STEP: {description}")
    print(f"CMD:  {' '.join(cmd)}")
    print(f"{'='*60}")

    result = subprocess.run(
        cmd,
        check=check,
        capture_output=capture_output,
        text=True,
    )

    if capture_output and result.stdout:
        print(result.stdout)
    if capture_output and result.stderr:
        print(result.stderr, file=sys.stderr)

    return result


def validate_requirements_file(requirements_path):
    """Validate that requirements.txt exists and pins all dependencies."""
    if not requirements_path.is_file():
        print(f"ERROR: {requirements_path} not found.")
        sys.exit(1)

    unpinned = []
    with open(requirements_path, "r") as f:
        for line_num, line in enumerate(f, 1):
            line = line.strip()
            if not line or line.startswith("#") or line.startswith("-"):
                continue
            # Check for pinned versions (==) or hash-verified installs
            if "==" not in line and "@" not in line:
                unpinned.append((line_num, line))

    if unpinned:
        print("WARNING: The following dependencies are not pinned to exact versions:")
        for line_num, dep in unpinned:
            print(f"  Line {line_num}: {dep}")
        print(
            "RECOMMENDATION: Pin all dependencies with '==' for reproducible builds."
        )
        print(
            "  Run: pip-compile --generate-hashes requirements.in -o requirements.txt"
        )
        # In strict mode, fail on unpinned deps
        if os.environ.get("STRICT_PINNING", "").lower() in ("1", "true", "yes"):
            print("ERROR: STRICT_PINNING is enabled. All dependencies must be pinned.")
            sys.exit(1)

    return requirements_path


def compute_file_hash(filepath):
    """Compute SHA-256 hash of a file for integrity verification."""
    sha256 = hashlib.sha256()
    with open(filepath, "rb") as f:
        for chunk in iter(lambda: f.read(8192), b""):
            sha256.update(chunk)
    return sha256.hexdigest()


def install_dependencies(requirements_path, venv_dir):
    """Install dependencies in a virtual environment with security checks."""
    print("\n>>> Creating virtual environment...")

    # Create a fresh virtual environment for clean, reproducible builds
    if venv_dir.exists():
        shutil.rmtree(venv_dir)

    run_command(
        [sys.executable, "-m", "venv", str(venv_dir)],
        "Creating virtual environment",
    )

    # Determine platform-appropriate pip path
    if sys.platform == "win32":
        pip_path = str(venv_dir / "Scripts" / "pip")
        python_path = str(venv_dir / "Scripts" / "python")
    else:
        pip_path = str(venv_dir / "bin" / "pip")
        python_path = str(venv_dir / "bin" / "python")

    # Upgrade pip itself to latest secure version
    run_command(
        [python_path, "-m", "pip", "install", "--upgrade", "pip"],
        "Upgrading pip to latest version",
    )

    # Build the install command with security flags
    install_cmd = [
        pip_path,
        "install",
        "--require-hashes" if _has_hashes(requirements_path) else None,
        "--no-cache-dir",  # Don't use cached packages; ensure fresh downloads
        "-r",
        str(requirements_path),
    ]
    # Filter out None entries
    install_cmd = [arg for arg in install_cmd if arg is not None]

    run_command(install_cmd, "Installing dependencies from requirements.txt")

    # Audit installed packages for known vulnerabilities
    audit_dependencies(pip_path, python_path)

    return python_path, pip_path


def _has_hashes(requirements_path):
    """Check if requirements.txt contains hash specifications."""
    with open(requirements_path, "r") as f:
        content = f.read()
    return "--hash=" in content


def audit_dependencies(pip_path, python_path):
    """Check installed packages for known vulnerabilities using pip-audit."""
    print("\n>>> Auditing dependencies for known vulnerabilities...")

    # Install pip-audit for vulnerability scanning
    result = run_command(
        [pip_path, "install", "pip-audit"],
        "Installing pip-audit for vulnerability scanning",
        check=False,
    )

    if result.returncode != 0:
        print("WARNING: Could not install pip-audit. Skipping vulnerability audit.")
        return

    audit_result = run_command(
        [python_path, "-m", "pip_audit", "--strict", "--desc"],
        "Running pip-audit vulnerability scan",
        check=False,
        capture_output=True,
    )

    if audit_result.returncode != 0:
        print("=" * 60)
        print("SECURITY ALERT: Vulnerabilities found in dependencies!")
        print("=" * 60)
        if audit_result.stdout:
            print(audit_result.stdout)
        if audit_result.stderr:
            print(audit_result.stderr)

        if os.environ.get("FAIL_ON_VULN", "true").lower() in ("1", "true", "yes"):
            print("ERROR: Failing build due to vulnerable dependencies.")
            print("Set FAIL_ON_VULN=false to override (not recommended).")
            sys.exit(1)
        else:
            print("WARNING: Continuing despite vulnerabilities (FAIL_ON_VULN=false).")
    else:
        print("All dependencies passed vulnerability audit.")


def check_for_outdated_dependencies(pip_path):
    """Report outdated dependencies to encourage timely updates."""
    print("\n>>> Checking for outdated dependencies...")

    result = run_command(
        [pip_path, "list", "--outdated", "--format=json"],
        "Checking for outdated packages",
        check=False,
        capture_output=True,
    )

    if result.returncode == 0 and result.stdout.strip():
        try:
            outdated = json.loads(result.stdout)
            if outdated:
                print(f"\nINFO: {len(outdated)} outdated package(s) detected:")
                print(f"  {'Package':<30} {'Current':<15} {'Latest':<15}")
                print(f"  {'-'*30} {'-'*15} {'-'*15}")
                for pkg in outdated:
                    print(
                        f"  {pkg['name']:<30} {pkg['version']:<15} {pkg['latest_version']:<15}"
                    )
                print(
                    "\nRECOMMENDATION: Update dependencies regularly to get security patches."
                )
                print(
                    "  Run: pip-compile --upgrade requirements.in -o requirements.txt"
                )

                max_outdated = int(os.environ.get("MAX_OUTDATED_DEPS", "0"))
                if max_outdated > 0 and len(outdated) > max_outdated:
                    print(
                        f"\nERROR: More than {max_outdated} outdated dependencies. "
                        "Update before deploying."
                    )
                    sys.exit(1)
            else:
                print("All dependencies are up to date.")
        except json.JSONDecodeError:
            print("WARNING: Could not parse outdated packages output.")
    else:
        print("All dependencies are up to date.")


def run_tests(python_path):
    """Run the application test suite."""
    print("\n>>> Running application tests...")

    # Determine test runner - prefer pytest if available
    test_result = run_command(
        [python_path, "-m", "pytest", "--version"],
        "Checking for pytest",
        check=False,
        capture_output=True,
    )

    if test_result.returncode == 0:
        run_command(
            [
                python_path,
                "-m",
                "pytest",
                "-v",
                "--tb=short",
                "--strict-markers",
                "-x",  # Stop on first failure for fast feedback
            ],
            "Running tests with pytest",
        )
    else:
        # Fall back to unittest
        run_command(
            [python_path, "-m", "unittest", "discover", "-s", "tests", "-v"],
            "Running tests with unittest",
        )

    print("All tests passed.")


def package_for_deployment(python_path, pip_path, project_dir, dist_dir):
    """Package the application for deployment."""
    print("\n>>> Packaging application for deployment...")

    # Clean previous build artifacts
    if dist_dir.exists():
        shutil.rmtree(dist_dir)
    dist_dir.mkdir(parents=True)

    build_timestamp = datetime.now(timezone.utc).strftime("%Y%m%d_%H%M%S")
    package_name = f"deployment_{build_timestamp}"
    package_dir = dist_dir / package_name

    # Create package structure
    package_dir.mkdir(parents=True)

    # Copy application source
    src_dirs = ["src", "app", "lib"]
    copied_src = False
    for src_dir_name in src_dirs:
        src_path = project_dir / src_dir_name
        if src_path.is_dir():
            shutil.copytree(src_path, package_dir / src_dir_name)
            copied_src = True

    # Also copy any top-level Python files (e.g., main.py, wsgi.py)
    for py_file in project_dir.glob("*.py"):
        if py_file.name.startswith("test_") or py_file.name == "setup.py":
            continue
        shutil.copy2(py_file, package_dir / py_file.name)
        copied_src = True

    if not copied_src:
        print(
            "WARNING: No application source directories found (looked for: src/, app/, lib/)."
        )

    # Copy configuration files
    config_files = [
        "requirements.txt",
        "Procfile",
        "runtime.txt",
        "app.yaml",
        "Dockerfile",
        ".env.example",
        "pyproject.toml",
        "setup.cfg",
    ]
    for config_file in config_files:
        config_path = project_dir / config_file
        if config_path.is_file():
            shutil.copy2(config_path, package_dir / config_file)

    # Export installed package versions for reproducibility (frozen requirements)
    frozen_output = run_command(
        [pip_path, "freeze"],
        "Freezing installed package versions",
        capture_output=True,
    )
    frozen_requirements_path = package_dir / "requirements.frozen.txt"
    with open(frozen_requirements_path, "w") as f:
        f.write(f"# Frozen at {build_timestamp} UTC\n")
        f.write(f"# Python {sys.version}\n")
        # Filter out pip-audit and other build-only tools
        build_tools = {"pip-audit", "pip", "setuptools", "wheel"}
        for line in frozen_output.stdout.strip().split("\n"):
            pkg_name = line.split("==")[0].lower().strip()
            if pkg_name not in build_tools:
                f.write(line + "\n")

    # Generate build manifest with integrity hashes
    manifest = {
        "build_timestamp": build_timestamp,
        "python_version": sys.version,
        "platform": sys.platform,
        "files": {},
    }

    for filepath in sorted(package_dir.rglob("*")):
        if filepath.is_file():
            rel_path = str(filepath.relative_to(package_dir))
            manifest["files"][rel_path] = {
                "sha256": compute_file_hash(filepath),
                "size": filepath.stat().st_size,
            }

    manifest_path = package_dir / "BUILD_MANIFEST.json"
    with open(manifest_path, "w") as f:
        json.dump(manifest, f, indent=2)

    # Create the deployment archive
    archive_path = dist_dir / package_name
    archive_file = shutil.make_archive(
        str(archive_path), "gztar", root_dir=str(dist_dir), base_dir=package_name
    )

    # Compute archive hash for verification during deployment
    archive_hash = compute_file_hash(archive_file)
    checksum_path = Path(archive_file + ".sha256")
    with open(checksum_path, "w") as f:
        f.write(f"{archive_hash}  {Path(archive_file).name}\n")

    # Clean up uncompressed package directory
    shutil.rmtree(package_dir)

    print(f"\nDeployment package created: {archive_file}")
    print(f"Package checksum (SHA-256): {archive_hash}")
    print(f"Checksum file: {checksum_path}")

    return archive_file


def main():
    """Main deployment pipeline."""
    print("=" * 60)
    print("DEPLOYMENT AUTOMATION PIPELINE")
    print(f"Started at: {datetime.now(timezone.utc).isoformat()}")
    print(f"Platform: {sys.platform}")
    print(f"Python: {sys.version}")
    print("=" * 60)

    # Determine project paths
    project_dir = Path(os.environ.get("PROJECT_DIR", ".")).resolve()
    requirements_path = project_dir / os.environ.get(
        "REQUIREMENTS_FILE", "requirements.txt"
    )
    venv_dir = project_dir / ".deploy_venv"
    dist_dir = project_dir / "dist"

    print(f"Project directory: {project_dir}")
    print(f"Requirements file: {requirements_path}")

    # Step 1: Validate requirements file
    validate_requirements_file(requirements_path)

    # Step 2: Install dependencies securely
    python_path, pip_path = install_dependencies(requirements_path, venv_dir)

    # Step 3: Check for outdated dependencies
    check_for_outdated_dependencies(pip_path)

    # Step 4: Run tests
    run_tests(python_path)

    # Step 5: Package for deployment
    archive_file = package_for_deployment(python_path, pip_path, project_dir, dist_dir)

    # Cleanup virtual environment (optional, saves disk in CI)
    if os.environ.get("CLEANUP_VENV", "true").lower() in ("1", "true", "yes"):
        print("\n>>> Cleaning up build virtual environment...")
        shutil.rmtree(venv_dir, ignore_errors=True)

    print("\n" + "=" * 60)
    print("DEPLOYMENT PIPELINE COMPLETED SUCCESSFULLY")
    print(f"Artifact: {archive_file}")
    print(f"Finished at: {datetime.now(timezone.utc).isoformat()}")
    print("=" * 60)

    return 0


if __name__ == "__main__":
    try:
        sys.exit(main())
    except subprocess.CalledProcessError as e:
        print(f"\nPIPELINE FAILED: Command returned exit code {e.returncode}")
        print(f"Command: {' '.join(e.cmd)}")
        sys.exit(e.returncode)
    except KeyboardInterrupt:
        print("\nPIPELINE INTERRUPTED by user.")
        sys.exit(130)
    except Exception as e:
        print(f"\nPIPELINE ERROR: {e}")
        sys.exit(1)